const staleDecisions = $('Get Stale Decisions').all().map(i => i.json);
const staleConstraints = $('Get Stale Constraints').all().map(i => i.json);
const staleTribal = $('Get Stale Tribal').all().map(i => i.json);
const stats = $('Get Knowledge Stats').first().json;

const today = new Date().toLocaleDateString('en-US', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

const totalStale = staleDecisions.length + staleConstraints.length + staleTribal.length;

let html = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <style>
    body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; line-height: 1.6; color: #1e293b; max-width: 650px; margin: 0 auto; padding: 20px; }
    .header { border-bottom: 2px solid #f59e0b; padding-bottom: 16px; margin-bottom: 24px; }
    .header h1 { margin: 0; font-size: 24px; color: #d97706; }
    .summary { display: flex; justify-content: space-around; background: #fef3c7; padding: 16px; border-radius: 8px; margin-bottom: 24px; }
    .stat { text-align: center; }
    .stat-value { font-size: 24px; font-weight: 700; color: #d97706; }
    .stat-label { font-size: 12px; color: #92400e; }
    .section { margin-bottom: 24px; }
    .section h2 { font-size: 16px; color: #78350f; border-bottom: 1px solid #fde68a; padding-bottom: 8px; margin-bottom: 12px; }
    .item { padding: 12px 16px; margin: 8px 0; background: #fff; border: 1px solid #fde68a; border-radius: 6px; }
    .item-title { font-weight: 600; color: #1e293b; }
    .item-meta { font-size: 12px; color: #64748b; margin-top: 4px; }
    .overdue { color: #dc2626; font-weight: 600; }
    .badge { display: inline-block; font-size: 11px; padding: 2px 8px; border-radius: 4px; margin-left: 8px; }
    .badge-domain { background: #dbeafe; color: #1d4ed8; }
    .badge-type { background: #f3e8ff; color: #7c3aed; }
    .action-link { display: inline-block; margin-top: 16px; padding: 12px 24px; background: #f59e0b; color: white; text-decoration: none; border-radius: 6px; font-weight: 600; }
    .action-link:hover { background: #d97706; }
    .footer { margin-top: 32px; text-align: center; font-size: 12px; color: #94a3b8; }
    .knowledge-stats { background: #f1f5f9; padding: 16px; border-radius: 8px; margin-top: 24px; }
    .knowledge-stats h3 { margin: 0 0 12px 0; font-size: 14px; color: #475569; }
    .stats-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 12px; }
    .mini-stat { text-align: center; }
    .mini-stat-value { font-size: 18px; font-weight: 600; color: #3b82f6; }
    .mini-stat-label { font-size: 11px; color: #64748b; }
  </style>
</head>
<body>
  <div class="header">
    <h1>Knowledge Review Needed</h1>
    <div style="color: #92400e;">${today}</div>
  </div>

  <div class="summary">
    <div class="stat"><div class="stat-value">${totalStale}</div><div class="stat-label">Items Need Review</div></div>
    <div class="stat"><div class="stat-value">${staleDecisions.length}</div><div class="stat-label">Decisions</div></div>
    <div class="stat"><div class="stat-value">${staleConstraints.length}</div><div class="stat-label">Constraints</div></div>
    <div class="stat"><div class="stat-value">${staleTribal.length}</div><div class="stat-label">Tribal</div></div>
  </div>
`;

if (staleDecisions.length > 0) {
  html += `
  <div class="section">
    <h2>Decisions Past Review Date</h2>
`;
  staleDecisions.slice(0, 10).forEach(d => {
    html += `
    <div class="item">
      <div class="item-title">${d.title}<span class="badge badge-domain">${d.domain}</span></div>
      <div class="item-meta">
        Review date: ${new Date(d.review_date).toLocaleDateString()}
        <span class="overdue">(${d.days_overdue} days overdue)</span>
      </div>
    </div>`;
  });
  if (staleDecisions.length > 10) {
    html += `<div class="item-meta">...and ${staleDecisions.length - 10} more</div>`;
  }
  html += '</div>';
}

if (staleConstraints.length > 0) {
  html += `
  <div class="section">
    <h2>Constraints Not Verified in 90+ Days</h2>
`;
  staleConstraints.slice(0, 10).forEach(c => {
    html += `
    <div class="item">
      <div class="item-title">${c.title}<span class="badge badge-domain">${c.domain}</span><span class="badge badge-type">${c.constraint_type}</span></div>
      <div class="item-meta">
        Last verified: ${c.last_verified_at ? new Date(c.last_verified_at).toLocaleDateString() : 'Never'}
        <span class="overdue">(${c.days_since_verified} days ago)</span>
      </div>
    </div>`;
  });
  if (staleConstraints.length > 10) {
    html += `<div class="item-meta">...and ${staleConstraints.length - 10} more</div>`;
  }
  html += '</div>';
}

if (staleTribal.length > 0) {
  html += `
  <div class="section">
    <h2>Tribal Knowledge Not Verified in 180+ Days</h2>
`;
  staleTribal.slice(0, 10).forEach(t => {
    html += `
    <div class="item">
      <div class="item-title">${t.title}<span class="badge badge-domain">${t.domain || 'general'}</span><span class="badge badge-type">${t.knowledge_type}</span></div>
      <div class="item-meta">
        Last verified: ${t.last_verified_at ? new Date(t.last_verified_at).toLocaleDateString() : 'Never'}
        <span class="overdue">(${t.days_since_verified} days ago)</span>
      </div>
    </div>`;
  });
  if (staleTribal.length > 10) {
    html += `<div class="item-meta">...and ${staleTribal.length - 10} more</div>`;
  }
  html += '</div>';
}

html += `
  <center>
    <p style="color: #78350f;">Run <code>/knowledge review</code> in Claude Code to review and update these items.</p>
  </center>

  <div class="knowledge-stats">
    <h3>Knowledge Base Overview</h3>
    <div class="stats-grid">
      <div class="mini-stat"><div class="mini-stat-value">${stats.active_decisions || 0}</div><div class="mini-stat-label">Decisions</div></div>
      <div class="mini-stat"><div class="mini-stat-value">${stats.total_lessons || 0}</div><div class="mini-stat-label">Lessons</div></div>
      <div class="mini-stat"><div class="mini-stat-value">${stats.tribal_items || 0}</div><div class="mini-stat-label">Tribal</div></div>
      <div class="mini-stat"><div class="mini-stat-value">${stats.active_constraints || 0}</div><div class="mini-stat-label">Constraints</div></div>
      <div class="mini-stat"><div class="mini-stat-value">${stats.active_dependencies || 0}</div><div class="mini-stat-label">Dependencies</div></div>
      <div class="mini-stat"><div class="mini-stat-value">${stats.current_processes || 0}</div><div class="mini-stat-label">Processes</div></div>
    </div>
  </div>

  <div class="footer">
    Generated by IAML Business OS Knowledge System
  </div>
</body>
</html>
`;

return {
  subject: `Knowledge Review: ${totalStale} items need attention`,
  html,
  totalStale,
  staleDecisions: staleDecisions.length,
  staleConstraints: staleConstraints.length,
  staleTribal: staleTribal.length
};
